def translate_numbered_heading(text: str) -> str:
    titled = re.fullmatch(r"(\d+(?:\.\d+)*\.\s*)(.+)", text)
    if titled and titled.group(2) in TITLE_TRANSLATIONS:
        return titled.group(1) + TITLE_TRANSLATIONS[titled.group(2)]
    heading_words = {
        "Example": "例",
        "Exercises": "练习",
        "Exercise": "练习",
        "Problem": "问题",
        "Solution": "解答",
        "Definition": "定义",
        "Lemma": "引理",
        "Theorem": "定理",
        "Proposition": "命题",
        "Corollary": "推论",
        "Proof": "证明",
    }
    for source, target in heading_words.items():
        match = re.fullmatch(r"(\d+(?:\.\d+)*\.\s*)" + re.escape(source), text)
        if match:
            return match.group(1) + target
    return ""


def load_items(path: Path) -> list[dict]:
    return json.loads(path.read_text(encoding="utf-8"))


def translate_item(item: dict) -> str:
    if item["id"] in ID_TRANSLATIONS:
        return ID_TRANSLATIONS[item["id"]]
    text = item["text"]
    if text in TITLE_TRANSLATIONS:
        return TITLE_TRANSLATIONS[text]
    if text in TEXT_TRANSLATIONS:
        return TEXT_TRANSLATIONS[text]
    numbered_heading = translate_numbered_heading(text)
    if numbered_heading:
        return numbered_heading
    return ""


def main() -> None:
    OUT_DIR.mkdir(parents=True, exist_ok=True)
    for template in sorted(TEMPLATE_DIR.glob("*.json")):
        items = load_items(template)
        any_translated = False
        for item in items:
            zh = translate_item(item)
            if zh:
                item["zh"] = zh
                any_translated = True
        if any_translated:
            (OUT_DIR / template.name).write_text(
                json.dumps(items, ensure_ascii=False, indent=2),
                encoding="utf-8",
            )


if __name__ == "__main__":
    main()
